const a = [
  {"id":391,"text":"Which nucleus of the hypothalamus is involved in the regulation of thirst and hunger?","explanation":"The **lateral nucleus** of the hypothalamus is involved in the regulation of both thirst and hunger.\r\n\r\n1. **Thirst Regulation:** The lateral hypothalamic area contains neurons that are responsible for triggering thirst sensations. When the body's water levels are low or when there is an increase in the concentration of solutes in the blood, these neurons are activated, leading to the sensation of thirst. Thirst is an essential mechanism that helps maintain proper water balance in the body.\r\n\r\n2. **Hunger Regulation:** The lateral hypothalamic area also plays a significant role in the regulation of hunger. Neurons in this region are involved in stimulating appetite and food intake. When these neurons are activated, it leads to feelings of hunger and an increased desire to eat.","reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 390.","responses":[{"text":"Lateral nucleus","correct":true,"visible":false},{"text":"Paraventricular nucleus","correct":false,"visible":false},{"text":"Supraoptic nucleus","correct":false,"visible":false},{"text":"Ventromedial nucleus","correct":false,"visible":false},{"text":"Suprachiasmatic nucleus","correct":false,"visible":false}]},{"id":2825,"text":"Which of the following is correct regarding insulin?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 974.","responses":[{"text":"Tertiary","correct":false,"visible":false},{"text":"Polymeric","correct":false,"visible":false},{"text":"Heterodimer","correct":true,"visible":false},{"text":"Monomeric","correct":false,"visible":false},{"text":"Homodimer","correct":false,"visible":false}]},{"id":2839,"text":"A 15-year-old boy presents to the outpatient department with backache, moon face, and truncal obesity. On examination, the child has elevated blood pressure and delayed reflexes. The laboratory results show increased cortisol levels. What is the most likely disease from which the boy is suffering?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 170.","responses":[{"text":"Pheochromocytoma","correct":false,"visible":false},{"text":"Cushing disease","correct":true,"visible":false},{"text":"Addison disease","correct":false,"visible":false},{"text":"Adrenal cortex tumor","correct":false,"visible":false},{"text":"Pseudo-Cushing syndrome","correct":false,"visible":false}]},{"id":2840,"text":"A 42-year-old woman presents to the clinic complaining of excessive facial hair and irregular menstrual cycles. On physical exam, the patient has truncal obesity and a characteristic 'moon-facies'. CT of the head shows a mass in the pituitary gland. What is the most likely diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Cushing disease","correct":true,"visible":false},{"text":"Waterhouse-Friderichsen syndrome","correct":false,"visible":false},{"text":"Polycystic ovarian syndrome (PCOS)","correct":false,"visible":false},{"text":"Cushing's syndrome","correct":false,"visible":false},{"text":"Prolactinoma","correct":false,"visible":false}]},{"id":2841,"text":"Which of the following symptoms characterizes diabetes insipidus?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 160.","responses":[{"text":"Frequent urination","correct":true,"visible":false},{"text":"Infertility","correct":false,"visible":false},{"text":"Sexual dysfunction","correct":false,"visible":false},{"text":"No urine","correct":false,"visible":false},{"text":"Acromegaly","correct":false,"visible":false}]},{"id":2842,"text":"In which of the following conditions is vasopressin indicated?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 687-688.","responses":[{"text":"Hypertension","correct":false,"visible":false},{"text":"Central diabetes insipidus","correct":true,"visible":false},{"text":"Diabetes mellitus","correct":false,"visible":false},{"text":"Tachycardia","correct":false,"visible":false},{"text":"Bronchospasm","correct":false,"visible":false}]},{"id":2843,"text":"Which of the following is the function of the growth hormone?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 935.","responses":[{"text":"Increase the release of somatostatin","correct":false,"visible":false},{"text":"Decrease amino acid uptake","correct":false,"visible":false},{"text":"Block the formation of somatomedin","correct":false,"visible":false},{"text":"Increase the synthesis of somatomedin","correct":true,"visible":false},{"text":"Decrease protein synthesis","correct":false,"visible":false}]},{"id":2844,"text":"A lady arrives at the clinic for the delivery of her baby. After the delivery, the lady has significant bleeding and exhibits post-partum symptoms of poor lactation, loss of pubic hair, and fatigue. Which of the following describes the condition the patient is suffering from?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 159-160.","responses":[{"text":"Sheehan syndrome","correct":true,"visible":false},{"text":"Pituitary adenoma","correct":false,"visible":false},{"text":"Prolactinoma","correct":false,"visible":false},{"text":"Empty sella syndrome","correct":false,"visible":false},{"text":"Acromegaly","correct":false,"visible":false}]},{"id":2861,"text":"A second-year MBBS student is given a slide of an endocrine gland that contains round and oval structures lined by cuboidal epithelium. Which of the following is most likely the endocrine gland?","explanation":"The endocrine gland that contains round and oval structures lined by cuboidal epithelium is most likely the **thyroid gland**.\r\n\r\nThe thyroid gland is a bilobed endocrine gland located in the anterior neck. Each lobe of the thyroid gland is composed of numerous spherical structures known as thyroid follicles. These follicles are lined by cuboidal epithelial cells called thyroid follicular cells. The follicular cells are responsible for producing and storing thyroid hormones, mainly thyroxine (T4) and triiodothyronine (T3).\r\n\r\nThe cuboidal shape of the follicular cells and the presence of the round and oval follicles are characteristic features of the thyroid gland. These hormones play a crucial role in regulating the body's metabolism, growth, and development.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 82, 430.","responses":[{"text":"Pancreas","correct":false,"visible":false},{"text":"Pituitary","correct":false,"visible":false},{"text":"Adrenal","correct":false,"visible":false},{"text":"Thyroid","correct":true,"visible":false},{"text":"Testes","correct":false,"visible":false}]},{"id":2907,"text":"Hyperthyroidism is characterized by which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1076.","responses":[{"text":"Brittle hair","correct":false,"visible":false},{"text":"Increase in body weight","correct":false,"visible":false},{"text":"Decrease in sweating","correct":false,"visible":false},{"text":"Cold intolerance","correct":false,"visible":false},{"text":"Increase in basal metabolic rate","correct":true,"visible":false}]},{"id":2908,"text":"What is the function of adenylyl cyclase?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 923.","responses":[{"text":"Conversion of ATP to cAMP","correct":true,"visible":false},{"text":"Conversion of ATP to cGMP","correct":false,"visible":false},{"text":"Conversion of cAMP to ATP","correct":false,"visible":false},{"text":"Activation of G protein","correct":false,"visible":false},{"text":"Conversion of ATP to AMP","correct":false,"visible":false}]},{"id":2910,"text":"Which of the following anterior pituitary hormone is also responsible for regulating another endocrine gland?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 931.","responses":[{"text":"Prolactin","correct":false,"visible":false},{"text":"Growth hormone","correct":false,"visible":false},{"text":"Antidiuretic hormone (ADH)","correct":false,"visible":false},{"text":"Melanocyte-stimulating hormone (MSH)","correct":false,"visible":false},{"text":"Adrenocorticotropic hormone (ACTH)","correct":true,"visible":false}]},{"id":2922,"text":"Which of the following explains why regular insulin is used in a hyperglycemic emergency?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 313.","responses":[{"text":"It does not form antibody","correct":false,"visible":false},{"text":"Human insulin is not allergic","correct":false,"visible":false},{"text":"It can be given intravenously for rapid onset of action","correct":true,"visible":false},{"text":"It has a delayed onset of action","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":2943,"text":"A hormone is a chemical messenger, which transmits signals between which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 6.","responses":[{"text":"From one artery to another","correct":false,"visible":false},{"text":"From one muscle to another","correct":false,"visible":false},{"text":"From one cell to another","correct":true,"visible":false},{"text":"From one membrane to another","correct":false,"visible":false},{"text":"From one tissue to another","correct":false,"visible":false}]},{"id":2944,"text":"In the 5 factor model of personality, conscientiousness represents which type of character?","explanation":null,"reference":null,"responses":[{"text":"Tense","correct":false,"visible":false},{"text":"Reliable, responsible","correct":true,"visible":false},{"text":"Anxious","correct":false,"visible":false},{"text":"Energetic","correct":false,"visible":false},{"text":"Wide interest","correct":false,"visible":false}]},{"id":2974,"text":"Which of the following is the most common pituitary disease?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1067.","responses":[{"text":"Pituitary adenoma","correct":true,"visible":false},{"text":"Empty sella syndrome","correct":false,"visible":false},{"text":"Sarcoidosis","correct":false,"visible":false},{"text":"Pituitary metastatic tumors","correct":false,"visible":false},{"text":"Pituitary apoplexy","correct":false,"visible":false}]},{"id":2975,"text":"Tetany is seen in which of the following conditions?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1097.","responses":[{"text":"Hypothyroidism","correct":false,"visible":false},{"text":"Hyperparathyroidism","correct":false,"visible":false},{"text":"Pseudohypoparathydroidism","correct":false,"visible":false},{"text":"Hypoparathyroidism","correct":true,"visible":false},{"text":"Hyperthyroidism","correct":false,"visible":false}]},{"id":2976,"text":"Gigantism is a disorder that results from the excessive production of growth hormone leading to a very tall height and large viscera. This condition is due to the hypersecretion from which of the following cells?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1071.","responses":[{"text":"Mammotrophs","correct":false,"visible":false},{"text":"Gonadotrophs","correct":false,"visible":false},{"text":"Thyrotrophs","correct":false,"visible":false},{"text":"Somatotrophs","correct":true,"visible":false},{"text":"Corticotrophs","correct":false,"visible":false}]},{"id":2977,"text":"Parathyroid hormone enhances 1-alpha-hydroxylase activity which in turn stimulates which of the following processes?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 390.","responses":[{"text":"Vitamin D synthesis","correct":true,"visible":false},{"text":"Calcium metabolism","correct":false,"visible":false},{"text":"Calcitonin synthesis","correct":false,"visible":false},{"text":"Vitamin D catabolism","correct":false,"visible":false},{"text":"Vitamin D absorption","correct":false,"visible":false}]},{"id":2988,"text":"What is the action of steroid hormone when it binds to its target cell receptor?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 925.","responses":[{"text":"It causes the formation of cyclic GMP","correct":false,"visible":false},{"text":"It causes the formation of releasing hormones","correct":false,"visible":false},{"text":"It causes the formation of cyclic AMP","correct":false,"visible":false},{"text":"It turns specific genes of the nuclear DNA on or off","correct":true,"visible":false},{"text":"It is converted into cholesterol, which acts as a second messenger","correct":false,"visible":false}]},{"id":2990,"text":"The thyroid gland is lined by which type of epithelium?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 82.","responses":[{"text":"Pseudostratified columnar","correct":false,"visible":false},{"text":"Transitional","correct":false,"visible":false},{"text":"Simple squamous","correct":false,"visible":false},{"text":"Simple cuboidal","correct":true,"visible":false},{"text":"Stratified cuboidal","correct":false,"visible":false}]},{"id":2991,"text":"Which of the following metabolic change is more prominent in type 1 diabetes mellitus?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 167.","responses":[{"text":"Decreased lipolysis","correct":false,"visible":false},{"text":"Increased gluconeogenesis","correct":true,"visible":false},{"text":"Increased lipogenesis","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Decreased ketogenesis","correct":false,"visible":false}]},{"id":3005,"text":"While reading the magnetic resonance imaging (MRI) report of a hypertensive patient, a radiologist noted that a vascular lesion was affecting the hypophyseal portal system. Which artery forms this portal system?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 416-417.","responses":[{"text":"Ophthalmic artery","correct":false,"visible":false},{"text":"Superior hypophyseal artery","correct":true,"visible":false},{"text":"Basilar artery","correct":false,"visible":false},{"text":"Anterior inferior cerebellar artery","correct":false,"visible":false},{"text":"Posterior communicating artery","correct":false,"visible":false}]},{"id":3009,"text":"What is the composition of insulin?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 308.","responses":[{"text":"Preproinsulin having 108 amino acids and proinsulin having 86 amino acids","correct":false,"visible":false},{"text":"A single polypeptide chain of 84 amino acids","correct":false,"visible":false},{"text":"An α chain having 21 amino acids and a β chain having 30 amino acids","correct":true,"visible":false},{"text":"An α chain having 108 amino acids and a β chain having 30 amino acids","correct":false,"visible":false},{"text":"A single polypeptide chain of 51 amino acids","correct":false,"visible":false}]},{"id":3012,"text":"A 62-year-old male presents to the clinic with complaints of weight gain and lethargy. He suffers from hypertension and ischemic heart disease, for which he is taking drugs. His TSH and FT4 levels are 21 mIU/L and 0.02 ng/dL, respectively. Considering drug-induced hypothyroidism, which of the following drug might be the most common cause?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 647.","responses":[{"text":"Amiodarone","correct":true,"visible":false},{"text":"Phenylbutazone","correct":false,"visible":false},{"text":"Interferon","correct":false,"visible":false},{"text":"Sulphasalazine","correct":false,"visible":false},{"text":"Interleukin blockers","correct":false,"visible":false}]},{"id":3013,"text":"Which of the following hormone has a diabetogenic effect?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 934.","responses":[{"text":"Oxytocin","correct":false,"visible":false},{"text":"Growth hormone","correct":true,"visible":false},{"text":"Thyroid hormone","correct":false,"visible":false},{"text":"Vasopressin","correct":false,"visible":false},{"text":"Insulin","correct":false,"visible":false}]},{"id":3014,"text":"Conversion of which of the following is an essential step in the formation of thyroid hormone?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 943.","responses":[{"text":"Thyroxine","correct":false,"visible":false},{"text":"Iodide to chloride","correct":false,"visible":false},{"text":"Iodide ions to oxidized form of iodine","correct":true,"visible":false},{"text":"Thyroglobulin","correct":false,"visible":false},{"text":"Iodide to sodium iodide","correct":false,"visible":false}]},{"id":3015,"text":"Which of the following leads to Addison disease?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1123.","responses":[{"text":"Secondary adrenal hypofunction","correct":false,"visible":false},{"text":"Tertiary disorder of the cortisol hormone system","correct":false,"visible":false},{"text":"Abnormal growth of the thyroid gland","correct":false,"visible":false},{"text":"Primary adrenocortical hypofunction","correct":true,"visible":false},{"text":"Functional disability of the hormone cortisol","correct":false,"visible":false}]},{"id":3016,"text":"A pathologist is observing a specimen from the parathyroid gland. He notices that the glandular cells are small with rounded central nuclei and pale eosinophilic or clear cytoplasm. These cells are arranged in clusters and form 80% of the total volume in normal adults. Which is the most likely cell type that the pathologist observed?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 433.","responses":[{"text":"Chief/principal cells","correct":true,"visible":false},{"text":"Follicular cells","correct":false,"visible":false},{"text":"Clear cells","correct":false,"visible":false},{"text":"Oxyphil cells","correct":false,"visible":false},{"text":"C cells","correct":false,"visible":false}]},{"id":3017,"text":"Which of the following involves excessive secretion of adrenocorticotropic hormone (ACTH)?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 171.","responses":[{"text":"Addison disease","correct":false,"visible":false},{"text":"Thyrotoxicosis","correct":false,"visible":false},{"text":"Cushing disease","correct":true,"visible":false},{"text":"Myxodema","correct":false,"visible":false},{"text":"Pheochromocytoma","correct":false,"visible":false}]},{"id":3018,"text":"What is the simplest parameter to define obesity in metabolic syndrome?","explanation":"In the context of metabolic syndrome, **waist circumference** is the simplest parameter used to define obesity. Metabolic syndrome is a cluster of risk factors that increase the risk of cardiovascular diseases and diabetes. Central obesity, which refers to excess fat accumulation around the waist, is a key component of metabolic syndrome.\r\n\r\nWaist circumference is a practical and non-invasive measurement that reflects the amount of visceral fat, which is the fat surrounding the abdominal organs. It is considered an indicator of abdominal obesity and an important predictor of metabolic abnormalities.\r\n\r\nThe cutoff values for defining central obesity vary based on population and ethnicity, but generally, a waist circumference above a certain threshold is indicative of central obesity. For example, in adults, a waist circumference greater than 40 inches (102 cm) in men and greater than 35 inches (88 cm) in women is often used to define central obesity in the context of metabolic syndrome.","reference":"(1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 700, 744. (2) Schunkert H, Markus MRP, Stritzke J, Preedy VR. Waist circumference and cardiovascular risk. Handbook of Anthropometry: Physical Measures of Human Form in Health and Disease. Published 2012. Accessed June 20, 2022. https://doi.org/10.1007/978-1-4419-1788-1_13","responses":[{"text":"Body mass index","correct":false,"visible":false},{"text":"Body weight","correct":false,"visible":false},{"text":"Waist hip ratio","correct":false,"visible":false},{"text":"Measurement of visceral fat by MRI scan","correct":false,"visible":false},{"text":"Waist circumference","correct":true,"visible":false}]},{"id":3019,"text":"What is the most important component of metabolic syndrome according to the International Diabetes Federation?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 447-448.","responses":[{"text":"Hypertriglyceridemia","correct":false,"visible":false},{"text":"Visceral obesity","correct":true,"visible":false},{"text":"Low HDL cholesterol","correct":false,"visible":false},{"text":"Impaired glucose tolerance test","correct":false,"visible":false},{"text":"Hypertension","correct":false,"visible":false}]},{"id":3020,"text":"A 40-year-old woman presents with 5 kg weight loss over 4 months, heat intolerance, and palpitations. On examination, there is diffuse thyroid enlargement. Serology shows TSH receptor antibodies. Which of the following is the correct diagnosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021:161.","responses":[{"text":"Hashimoto's thyroiditis","correct":false,"visible":false},{"text":"De Quervain's thyroiditis","correct":false,"visible":false},{"text":"Palpation thyroiditis","correct":false,"visible":false},{"text":"Grave's disease","correct":true,"visible":false},{"text":"Lymphocytic thyroiditis","correct":false,"visible":false}]},{"id":3057,"text":"Hyperactivity of which of the following endocrine glands increases cortisol secretion?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 917.","responses":[{"text":"Posterior pituitary gland","correct":false,"visible":false},{"text":"Anterior pituitary gland","correct":true,"visible":false},{"text":"Pineal gland","correct":false,"visible":false},{"text":"Pancreas","correct":false,"visible":false},{"text":"Parathyroid gland","correct":false,"visible":false}]},{"id":3058,"text":"Measurement of which of these confirms the excessive secretion of catecholamines?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 286.","responses":[{"text":"Vanillylmandelic acid (VMA)","correct":true,"visible":false},{"text":"Noradrenaline","correct":false,"visible":false},{"text":"Adrenaline","correct":false,"visible":false},{"text":"Dopamine","correct":false,"visible":false},{"text":"Valine methyl acid","correct":false,"visible":false}]},{"id":3059,"text":"Which of the following is the most sensitive test for myxedema?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1078.","responses":[{"text":"Triiodothyronine (T3)","correct":false,"visible":false},{"text":"Thyrotropin-releasing hormone (TRH)","correct":false,"visible":false},{"text":"Thyroid stimulating hormone  (TSH)","correct":true,"visible":false},{"text":"Thyroxine (T4)","correct":false,"visible":false},{"text":"Free T3","correct":false,"visible":false}]},{"id":3061,"text":"A pregnant woman, with no previous history of diabetes, started developing hyperglycemia, coupled with polyuria and glycosuria in her 2nd trimester. She is brought to the emergency room on the 29th week of gestation and an emergency caesarian is performed. Her baby is born overweight and develops seizures immediately after birth. Which of the following is the most likely reason for the baby's condition?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1105.","responses":[{"text":"Maturity onset diabetes of young","correct":false,"visible":false},{"text":"Type 2 diabetes mellitus","correct":false,"visible":false},{"text":"Type 1 diabetes mellitus","correct":false,"visible":false},{"text":"Gestational diabetes","correct":true,"visible":false},{"text":"Neonatal diabetes","correct":false,"visible":false}]},{"id":3062,"text":"A 25-year-old male comes to the outpatient department with complaints of intermittent headache and nausea for 4 months. On examination of the eyes, he has slightly impaired vision and diplopia. What is the most appropriate diagnosis for this patient?","explanation":"Based on the patient's clinical presentation, the most appropriate diagnosis for this 25-year-old male is a **pituitary adenoma**. Pituitary adenomas are benign tumors that arise from the cells of the anterior pituitary gland. They can cause various symptoms depending on their size and hormone-secreting capabilities.\r\n\r\nThe intermittent headache and nausea can be attributed to the tumor's mass effect, leading to increased intracranial pressure. The slightly impaired vision and diplopia (double vision) are likely due to compression of the optic chiasm and adjacent structures by the enlarging pituitary adenoma.\r\n\r\nPituitary adenomas can be classified based on the hormones they produce. The most common type is a **prolactin-secreting adenoma** (prolactinoma), which can cause hyperprolactinemia leading to reproductive and menstrual disturbances.","reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1070.","responses":[{"text":"Hypothalamic ischemia","correct":false,"visible":false},{"text":"Pituitary adenoma","correct":true,"visible":false},{"text":"Corneal infection","correct":false,"visible":false},{"text":"Ophthalmic inflammation","correct":false,"visible":false},{"text":"Retinal damage","correct":false,"visible":false}]},{"id":3063,"text":"Hormones of the adrenal medulla bind to which of these receptors?","explanation":null,"reference":null,"responses":[{"text":"Dopamine receptors","correct":false,"visible":false},{"text":"Glycine","correct":false,"visible":false},{"text":"Adrenergic receptors","correct":true,"visible":false},{"text":"Muscarinic receptor","correct":false,"visible":false},{"text":"Substance P","correct":false,"visible":false}]},{"id":3065,"text":"Which of these is true for the oxytocin hormone?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 940.","responses":[{"text":"It causes development of the mammary glands","correct":false,"visible":false},{"text":"It inhibits milk ejection","correct":false,"visible":false},{"text":"It is synthesized by the preoptic nuclei of hypothalamus","correct":false,"visible":false},{"text":"It is increased during labour","correct":true,"visible":false},{"text":"It is a polypeptide containing 195 amino acids","correct":false,"visible":false}]},{"id":3074,"text":"In thyroid follicles along with the follicular cells, parafollicular cells are found either individually or in clusters. Which of the following hormone is produced by these parafollicular cells?","explanation":null,"reference":null,"responses":[{"text":"Thyrotropin","correct":false,"visible":false},{"text":"Calcitonin","correct":true,"visible":false},{"text":"Thyroxin","correct":false,"visible":false},{"text":"Parathyroid hormone","correct":false,"visible":false},{"text":"Tyrosine","correct":false,"visible":false}]},{"id":3075,"text":"Which one of the following is considered a rich source of iodine in the human diet?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 406.","responses":[{"text":"Water","correct":false,"visible":false},{"text":"Seafood","correct":true,"visible":false},{"text":"Vegetables","correct":false,"visible":false},{"text":"Dairy products","correct":false,"visible":false},{"text":"Eggs","correct":false,"visible":false}]},{"id":3078,"text":"Iodine deficiency, a common micronutrient deficiency, can be prevented by incorporating which of these in the diet?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 406-407.","responses":[{"text":"Dairy products","correct":false,"visible":false},{"text":"Polished rice","correct":false,"visible":false},{"text":"Iodized salt","correct":true,"visible":false},{"text":"Common salt","correct":false,"visible":false},{"text":"Vegetable oil","correct":false,"visible":false}]},{"id":3083,"text":"What is the embryonic source of pancreatic development?","explanation":"The **pancreatic buds** are outgrowths from the foregut endoderm.\r\n\r\nInitially, two buds are formed: the **dorsal pancreatic bud** and the **ventral pancreatic bud**. The dorsal bud arises from the dorsal wall of the foregut, while the ventral bud arises from the ventral wall, just below the liver. These buds undergo further growth and migration.\r\n\r\nDuring development, the ventral bud rotates and fuses with the dorsal bud. As a result, the main pancreatic duct is formed from the duct of the ventral bud, while the body and tail of the pancreas develop from the dorsal bud. The head of the pancreas forms from both buds.","reference":"Sadler TW. Langman’s Medical Embryology. 14th ed. Wolters Kluwer; 2018: 244.","responses":[{"text":"Annular bud","correct":false,"visible":false},{"text":"Ventral bud","correct":false,"visible":false},{"text":"Both dorsal and ventral buds","correct":true,"visible":false},{"text":"Hepatic bud","correct":false,"visible":false},{"text":"Dorsal bud","correct":false,"visible":false}]},{"id":3084,"text":"Which of the following releases thyrotropin?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 948.","responses":[{"text":"Anterior pituitary gland","correct":true,"visible":false},{"text":"Posterior pituitary gland","correct":false,"visible":false},{"text":"Spleen","correct":false,"visible":false},{"text":"Thyroid gland","correct":false,"visible":false},{"text":"Thymus gland","correct":false,"visible":false}]},{"id":3096,"text":"Where is the antidiuretic hormone synthesized?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 376.","responses":[{"text":"Paraventricular nuclei of hypothalamus","correct":false,"visible":false},{"text":"Basal ganglia","correct":false,"visible":false},{"text":"Supraoptic nucleus of hypothalamus","correct":false,"visible":false},{"text":"Limbic system","correct":false,"visible":false},{"text":"Supraoptic and paraventricular nuclei of hypothalamus","correct":true,"visible":false}]},{"id":3099,"text":"The accessory duct of the pancreas is formed from which of the following?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 219.","responses":[{"text":"Ventral bud duct fusion with the distal part of the pancreas","correct":false,"visible":false},{"text":"Proximal part of the dorsal bud","correct":true,"visible":false},{"text":"Proximal part of the ventral bud","correct":false,"visible":false},{"text":"Ventral pancreatic bud","correct":false,"visible":false},{"text":"Distal part of the dorsal bud","correct":false,"visible":false}]},{"id":3103,"text":"A 35-year-old female went to see her doctor because she had been feeling hot lately and was sweating at night. Her T3 and T4 levels were found to be high, whereas her TSH level was low. What is the most likely diagnosis made by the doctor?","explanation":"The clinical scenario described in the case is characteristic of **primary hyperthyroidism**, also known as **thyrotoxicosis**. In this condition, the thyroid gland itself is overproducing thyroid hormones (T3 and T4), leading to an increased concentration of these hormones in the bloodstream. The key laboratory findings in primary hyperthyroidism are high levels of T3 and T4 and low levels of thyroid-stimulating hormone (TSH).\r\n\r\n**Possible Causes of Primary Hyperthyroidism:**\r\n- **Graves' Disease:** An autoimmune disorder where autoantibodies stimulate the thyroid gland to produce excessive hormones.\r\n- **Toxic Multinodular Goiter:** The presence of multiple nodules in the thyroid gland, some of which are autonomously producing hormones.\r\n- **Toxic Adenoma:** A single thyroid nodule that autonomously produces excessive hormones.\r\n\r\n**Differential Diagnosis:**\r\n- **Pituitary Adenoma:** A tumor of the pituitary gland that could lead to increased TSH secretion, causing secondary hyperthyroidism.\r\n- **Secondary Hyperthyroidism:** Excessive TSH secretion from the pituitary gland, leading to increased thyroid hormone production.\r\n- **Hypothyroidism:** Low T3 and T4 levels and elevated TSH levels are characteristic of this condition.\r\n- **Myxedema:** A severe form of hypothyroidism, not applicable in this case.","reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 346.","responses":[{"text":"Secondary hyperthyroidism","correct":false,"visible":false},{"text":"Primary hyperthyroidism","correct":true,"visible":false},{"text":"Pituitary adenoma","correct":false,"visible":false},{"text":"Hypothyroidism","correct":false,"visible":false},{"text":"Myxedema","correct":false,"visible":false}]},{"id":3105,"text":"Which of the following does not act as a second messenger in a hormone's action?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 923-925.","responses":[{"text":"cGMP","correct":false,"visible":false},{"text":"Calcium","correct":false,"visible":false},{"text":"Phosphatidylinositol","correct":false,"visible":false},{"text":"cAMP","correct":false,"visible":false},{"text":"Retinoic acid","correct":true,"visible":false}]},{"id":3107,"text":"The superior parathyroid gland developed from which of the following?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 163.","responses":[{"text":"3rd pharyngeal arch","correct":false,"visible":false},{"text":"1st pharyngeal arch","correct":false,"visible":false},{"text":"3rd pharyngeal pouch","correct":false,"visible":false},{"text":"1st pharyngeal pouch","correct":false,"visible":false},{"text":"4th pharyngeal pouch","correct":true,"visible":false}]},{"id":3109,"text":"Rate limiting step in the synthesis of adrenal steroid hormones is the conversion of cholesterol to pregnenolone. Which enzyme and coenzyme are required for this reaction?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 237.","responses":[{"text":"17-α-hydroxylase, NADPH, O2","correct":false,"visible":false},{"text":"11-β-hydroxylase, NADH, O2","correct":false,"visible":false},{"text":"Desmolase, NADPH, O2","correct":true,"visible":false},{"text":"Desmolase, FADH, O2","correct":false,"visible":false},{"text":"Desmolase, NADH, O2","correct":false,"visible":false}]},{"id":3113,"text":"A patient diagnosed with acromegaly typically presents with which of the following?","explanation":"Patients with acromegaly typically present with gradual and insidious development of specific features. These include enlargement of hands and feet, coarsening of facial features, soft tissue swelling, joint pain, excessive sweating, and headaches.\r\n\r\nOne of the key metabolic abnormalities in acromegaly is **insulin resistance**. Despite increased GH promoting lipolysis, protein synthesis, and gluconeogenesis, tissues become less responsive to insulin. This results in impaired glucose uptake, leading to elevated blood glucose levels. The presence of insulin resistance may contribute to the increased risk of diabetes mellitus in patients with acromegaly.","reference":"(1) Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 986.\r\n\r\n(2) Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 335, 345.","responses":[{"text":"Decreased lipolysis","correct":false,"visible":false},{"text":"Decreased gluconeogenesis","correct":false,"visible":false},{"text":"Insulin resistance","correct":true,"visible":false},{"text":"Decreased protein synthesis","correct":false,"visible":false},{"text":"Hypoglycemia","correct":false,"visible":false}]},{"id":3114,"text":"Which of these controls the secretion of the thyroid-stimulating hormone (TSH)?","explanation":null,"reference":null,"responses":[{"text":"Osmoreceptors","correct":false,"visible":false},{"text":"Basal ganglia","correct":false,"visible":false},{"text":"Mechanoreceptors","correct":false,"visible":false},{"text":"Hypothalamus","correct":true,"visible":false},{"text":"Thalamus","correct":false,"visible":false}]},{"id":3115,"text":"Cholesterol is the precursor for all lipid-soluble hormones except which of the following?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 237.","responses":[{"text":"Retinoic acid","correct":true,"visible":false},{"text":"Progesterone","correct":false,"visible":false},{"text":"Estrogen","correct":false,"visible":false},{"text":"Glucocorticoid","correct":false,"visible":false},{"text":"Testosterone","correct":false,"visible":false}]},{"id":3118,"text":"Genetic abnormalities are associated with pituitary adenomas. Which of the following is the most common genetic abnormality in pituitary adenomas?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1068.","responses":[{"text":"G-protein mutation","correct":true,"visible":false},{"text":"Defect in retinoblastoma","correct":false,"visible":false},{"text":"cAMP formation mutation","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"GDP formation mutation","correct":false,"visible":false}]},{"id":3120,"text":"What do the delta cells of islets of Langerhans secrete?","explanation":null,"reference":null,"responses":[{"text":"Insulin","correct":false,"visible":false},{"text":"Glucagon","correct":false,"visible":false},{"text":"Epinephrine","correct":false,"visible":false},{"text":"Cholecystokinin","correct":false,"visible":false},{"text":"Somatostatin","correct":true,"visible":false}]},{"id":3122,"text":"Which of the following greatly increases aldosterone secretion?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 961.","responses":[{"text":"ACTH from anterior pituitary gland","correct":false,"visible":false},{"text":"Decreased activity of renin-angiotensin system","correct":false,"visible":false},{"text":"Increased Cl- ion concentration in extracellular fluid","correct":false,"visible":false},{"text":"Increased Na+ ion concentration in extracellular fluid","correct":false,"visible":false},{"text":"Increased K+ ion concentration in extracellular fluid","correct":true,"visible":false}]},{"id":3123,"text":"The inferior parathyroid glands develop from which of the following?","explanation":"The parathyroid glands, which are responsible for regulating calcium levels in the body, develop from the pharyngeal pouches during embryonic development. The superior parathyroid glands arise from the **fourth pharyngeal pouch**, while the **inferior parathyroid glands** develop from the **dorsal wing of the third pharyngeal pouch**.\r\n\r\n**Embryonic Development of Parathyroid Glands:**\r\n1. Superior Parathyroid Glands: Develop from the **fourth pharyngeal pouch**, which also gives rise to the ultimobranchial body, the precursor of the parafollicular (C) cells of the thyroid gland.\r\n2. Inferior Parathyroid Glands: Arise from the **dorsal wing of the third pharyngeal pouch**, along with the thymus, which develops from the ventral wing of the same pouch.","reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 163.","responses":[{"text":"Dorsal 2nd pharyngeal pouch","correct":false,"visible":false},{"text":"Dorsal 3rd pharyngeal pouch","correct":true,"visible":false},{"text":"Dorsal 4th pharyngeal pouch","correct":false,"visible":false},{"text":"Ventral 3rd pharyngeal pouch","correct":false,"visible":false},{"text":"Ventral 4th pharyngeal pouch","correct":false,"visible":false}]},{"id":3124,"text":"Which of the following is incorrect regarding congenital adrenal hyperplasia (CAH)?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1120.","responses":[{"text":"Masculinization of female external genitalia","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Autosomal recessive disorder","correct":false,"visible":false},{"text":"Increases in adrenal androgen","correct":false,"visible":false},{"text":"Autosomal dominant disorder","correct":true,"visible":false}]},{"id":3125,"text":"Which of the following arteries doesn't supply the adrenal medulla?","explanation":null,"reference":null,"responses":[{"text":"Superior suprarenal arteries","correct":false,"visible":false},{"text":"Middle suprarenal arteries","correct":false,"visible":false},{"text":"Inferior phrenic artery","correct":false,"visible":false},{"text":"Long cortical arteries","correct":true,"visible":false},{"text":"Inferior suprarenal arteries","correct":false,"visible":false}]},{"id":3126,"text":"A 45-year-old woman was diagnosed with central diabetes insipidus. On enquiring, the physician informed the lady that the cause of the disease was deficiency of vasopressin from the pituitary gland. Which lobe of the pituitary gland releases this hormone?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 929.","responses":[{"text":"Pars distalis","correct":false,"visible":false},{"text":"Pars anterior","correct":false,"visible":false},{"text":"Adenohypophysis","correct":false,"visible":false},{"text":"Pars intermedia","correct":false,"visible":false},{"text":"Neurohypophysis","correct":true,"visible":false}]},{"id":3127,"text":"Which of the following is true for Addison disease?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 172.","responses":[{"text":"Occurs due to hyperfunction of adrenal gland","correct":false,"visible":false},{"text":"Occurs due to hyperfunction of pituitary gland","correct":false,"visible":false},{"text":"Infectious diseases are the major cause","correct":false,"visible":false},{"text":"Occurs due to hypofunction of adrenal gland","correct":true,"visible":false},{"text":"Primary disease of adrenal medulla","correct":false,"visible":false}]},{"id":3128,"text":"Which of the following inhibits the secretion of insulin?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 981.","responses":[{"text":"Gastric inhibitory polypeptide (GIP)","correct":false,"visible":false},{"text":"Cholecystokinin (CCK)","correct":false,"visible":false},{"text":"Increased blood glucose","correct":false,"visible":false},{"text":"Glucagon","correct":false,"visible":false},{"text":"Decreased blood glucose","correct":true,"visible":false}]},{"id":3148,"text":"What are the main clinical features of a prolactinoma?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 159.","responses":[{"text":"Acne and weight gain","correct":false,"visible":false},{"text":"Hyperpigmentation and decreased libido","correct":false,"visible":false},{"text":"Galactorrhea, amenorrhea, and infertility","correct":true,"visible":false},{"text":"Vision disturbance, headaches, and mood swings","correct":false,"visible":false},{"text":"Acromegaly, hyperostosis, and prognathism","correct":false,"visible":false}]},{"id":3150,"text":"Which one of the following is not a feature of centroacinar cells?","explanation":"The answer **\"They surround the serous acini\" is correct** because centroacinar cells are not located around the serous acini. Instead, they are found at the center of the serous acini, acting as a bridge between the acini and the intercalated ducts. Centroacinar cells are specialized cells that play a critical role in the exocrine function of the pancreas. They are involved in the production of bicarbonate-rich fluid, which helps neutralize the acidic chyme entering the small intestine from the stomach. This alkaline fluid aids in creating an optimal environment for pancreatic enzymes to function and assists in the digestion of nutrients.","reference":"(1) Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 333.\r\n\r\n(2) Young B, O’Dowd G, Woodford P. Wheater’s Functional Histology: A Text and Colour Atlas. 6th ed. Churchill Livingston/Elsevier; 2014: 288.","responses":[{"text":"They lack secretory granules and basophilic striations","correct":false,"visible":false},{"text":"They are continuous with the epithelium lining the intercalated ducts","correct":false,"visible":false},{"text":"They lie inside the serous acini","correct":false,"visible":false},{"text":"They are epithelial cells","correct":false,"visible":false},{"text":"They surround the serous acini","correct":true,"visible":false}]},{"id":3151,"text":"Which of the following hormone uses the adenylyl cyclase-cyclic AMP pathway?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 924.","responses":[{"text":"Parathyroid hormone","correct":true,"visible":false},{"text":"Testosterone","correct":false,"visible":false},{"text":"Oxytocin","correct":false,"visible":false},{"text":"Thyroxine","correct":false,"visible":false},{"text":"Growth hormone","correct":false,"visible":false}]},{"id":3152,"text":"Which of the following hormone binds to the intracellular receptor?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 923.","responses":[{"text":"Calcitriol","correct":true,"visible":false},{"text":"Insulin","correct":false,"visible":false},{"text":"Adrenaline","correct":false,"visible":false},{"text":"Oxytocin","correct":false,"visible":false},{"text":"Gastrin","correct":false,"visible":false}]},{"id":3153,"text":"When islets of Langerhans are observed under a compound microscope, cells in the center seem to have a higher percentage than the peripheral ones. Which cell type is present in the center?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 427.","responses":[{"text":"PP cells","correct":false,"visible":false},{"text":"Alpha cells","correct":false,"visible":false},{"text":"Serous cells","correct":false,"visible":false},{"text":"Beta cells","correct":true,"visible":false},{"text":"Delta cells","correct":false,"visible":false}]},{"id":3155,"text":"Which of the following is a peptide hormone?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 917.","responses":[{"text":"Estradiol","correct":false,"visible":false},{"text":"Testosterone","correct":false,"visible":false},{"text":"Progesterone","correct":false,"visible":false},{"text":"Cortisol","correct":false,"visible":false},{"text":"Glucagon","correct":true,"visible":false}]},{"id":3156,"text":"In muscles, what is the action of insulin on carbohydrate metabolism?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 975.","responses":[{"text":"Stimulates glucose uptake via GLUT4","correct":true,"visible":false},{"text":"Decreases glycogen synthesis","correct":false,"visible":false},{"text":"Decreases glucose uptake","correct":false,"visible":false},{"text":"Stimulates glucose uptake via GLUT2","correct":false,"visible":false},{"text":"Opens K+ channels","correct":false,"visible":false}]},{"id":3160,"text":"Which of the following causes the inhibition of insulin secretion?","explanation":null,"reference":null,"responses":[{"text":"Cholecystokinin","correct":false,"visible":false},{"text":"Increased serum amino acids","correct":false,"visible":false},{"text":"Stress","correct":true,"visible":false},{"text":"Increased serum free fatty acids","correct":false,"visible":false},{"text":"Hyperglycemia","correct":false,"visible":false}]},{"id":3161,"text":"Which of the following characterizes insulin resistance?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 984.","responses":[{"text":"Receptor defect","correct":false,"visible":false},{"text":"Increased synthesis of insulin","correct":false,"visible":false},{"text":"Increased ketogenesis","correct":false,"visible":false},{"text":"Hyperlipidemia","correct":false,"visible":false},{"text":"Decreased action of insulin","correct":true,"visible":false}]},{"id":3162,"text":"Which of the following is incorrect regarding the pituitary gland?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 398-399.","responses":[{"text":"Adenohypophysis develops from ectodermal roof of stomodeum","correct":false,"visible":false},{"text":"Adenohypophysis is the largest part of the gland","correct":false,"visible":false},{"text":"Functionally adenohypophysis is different from neurohypophysis","correct":false,"visible":false},{"text":"Pars intermedia is a remnant of lumen of Rathke's pouch","correct":false,"visible":false},{"text":"Pars tuberalis is downward extension of pars distalis","correct":true,"visible":false}]},{"id":3168,"text":"A 6-month-old baby boy was diagnosed with thyroid hormone deficiency. What is the most appropriate medical terminology used for this patient?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 162.","responses":[{"text":"Cushingoid","correct":false,"visible":false},{"text":"Dwarfism","correct":false,"visible":false},{"text":"Myxedema","correct":false,"visible":false},{"text":"Cretinism","correct":true,"visible":false},{"text":"Acromegaly","correct":false,"visible":false}]},{"id":3169,"text":"Which of the following statement is incorrect regarding the pancreas?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 334.","responses":[{"text":"The exocrine portion is composed of compound acinar glands","correct":false,"visible":false},{"text":"Acinar cells have zymogen granules","correct":false,"visible":false},{"text":"Intercalated ducts have centroacinar cells","correct":false,"visible":false},{"text":"Its intercalated ducts open into striated ducts","correct":true,"visible":false},{"text":"Under electron microscope, the golgi apparatus is supra nuclear in position","correct":false,"visible":false}]},{"id":3171,"text":"Glucocorticoids have an enhancing effect on free fatty acids in plasma through which of the following mechanisms?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 708.","responses":[{"text":"Increased vascular permeability","correct":false,"visible":false},{"text":"Increased lipolysis by activation of hormone-sensitive triacylglycerol (TAG) lipase","correct":true,"visible":false},{"text":"Decreased fat deposition","correct":false,"visible":false},{"text":"By an increase in adipose accumulation of fatty acids","correct":false,"visible":false},{"text":"By increased absorption from the gastrointestinal tract (GIT)","correct":false,"visible":false}]},{"id":3173,"text":"Which is the first endocrine gland to develop in an embryo, approximately 24 days after fertilization?","explanation":"The **thyroid gland** is the first endocrine gland to develop in an embryo, approximately 24 days after fertilization. During embryonic development, the thyroid gland originates from an endodermal structure called the **thyroid diverticulum** or **thyroid primordium**. The diverticulum arises from the floor of the primitive pharynx and descends inferiorly to its final location in the neck.\r\n\r\nAround the 24th day of gestation, the thyroid diverticulum begins to appear as an epithelial proliferation in the pharyngeal floor. As development progresses, it elongates and migrates caudally to reach the anterior neck region, where it eventually becomes the thyroid gland. The gland's descent and migration are guided by a connective tissue structure known as the **thyroglossal duct**.","reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 168.","responses":[{"text":"Pituitary","correct":false,"visible":false},{"text":"Pancreas","correct":false,"visible":false},{"text":"Thyroid gland","correct":true,"visible":false},{"text":"Hypothalamus","correct":false,"visible":false},{"text":"Parathyroid gland","correct":false,"visible":false}]},{"id":3174,"text":"Where are the primary receptors for steroid hormone present?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 920.","responses":[{"text":"Nucleus","correct":false,"visible":false},{"text":"Endoplasmic reticulum","correct":false,"visible":false},{"text":"Cytoplasm or nucleus","correct":true,"visible":false},{"text":"Nuclear membrane","correct":false,"visible":false},{"text":"Cell membrane","correct":false,"visible":false}]},{"id":3178,"text":"Which two antagonist pancreatic hormones are primarily responsible for controlling the blood glucose level?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 973.","responses":[{"text":"Insulin and somatostatin","correct":false,"visible":false},{"text":"Insulin and growth hormone","correct":false,"visible":false},{"text":"Insulin and cortisol","correct":false,"visible":false},{"text":"Thyroid hormone and glucagon","correct":false,"visible":false},{"text":"Insulin and glucagon","correct":true,"visible":false}]},{"id":3179,"text":"Which hormone mainly affects the tubular reabsorption of sodium?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 969.","responses":[{"text":"Adrenocorticotropic Hormone (ACTH)","correct":false,"visible":false},{"text":"Glucocorticoids","correct":false,"visible":false},{"text":"Cortisol","correct":false,"visible":false},{"text":"Aldosterone","correct":true,"visible":false},{"text":"Luteinizing hormone (LH)","correct":false,"visible":false}]},{"id":3182,"text":"Which is incorrect about the salivary glands?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 329.","responses":[{"text":"Striated ducts contribute to hypotonicity of saliva","correct":false,"visible":false},{"text":"IgA present in saliva is formed by plasma cells, present in lobular connective tissue","correct":false,"visible":false},{"text":"Submandibular gland is predominantly a serous gland","correct":false,"visible":false},{"text":"Myoepithelial cells are absent in submandibular gland","correct":true,"visible":false},{"text":"Serous demilunes are also present in sublingual gland","correct":false,"visible":false}]},{"id":3183,"text":"A 39-year-old man with insulin-dependent diabetes mellitus is brought to the emergency department after collapsing in a shopping mall. His blood sugar is 589 mg/dL. Which of the following preparations will have the least effect on his blood sugar level?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 314-315.","responses":[{"text":"Neutral protamine hagedorn (NPH) insulin","correct":false,"visible":false},{"text":"Insulin glulisine","correct":false,"visible":false},{"text":"Insulin glargine","correct":true,"visible":false},{"text":"Insulin aspart","correct":false,"visible":false},{"text":"Insulin lispro","correct":false,"visible":false}]},{"id":3186,"text":"An old lady with a diagnosis of hyperthyroidism undergoes a thyroid scan. The findings show increased uptake of radioactive iodine in a solitary circumscribed area. Which of the following is the most likely diagnosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1085.","responses":[{"text":"Hurthle cell (oxyphil) adenoma","correct":false,"visible":false},{"text":"Thyroiditis","correct":false,"visible":false},{"text":"Colloid nodule","correct":false,"visible":false},{"text":"Follicular adenoma","correct":false,"visible":false},{"text":"Toxic adenoma","correct":true,"visible":false}]},{"id":3187,"text":"On which of the following cells do aldosterone act to increase absorption of sodium and secretion of potassium?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 959.","responses":[{"text":"Renal tubular epithelial cells","correct":false,"visible":false},{"text":"Juxtaglomerular apparatus cells","correct":false,"visible":false},{"text":"Principal cells of collecting tubules","correct":true,"visible":false},{"text":"Macula densa cells","correct":false,"visible":false},{"text":"Intercalated cells of distal tubules","correct":false,"visible":false}]},{"id":3188,"text":"Which of the following hormone antagonizes the action of insulin?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 917.","responses":[{"text":"Follicle stimulating hormone (FSH)","correct":false,"visible":false},{"text":"Prolactin","correct":false,"visible":false},{"text":"Thyroid hormone","correct":false,"visible":false},{"text":"Glucagon","correct":true,"visible":false},{"text":"Luteinizing hormone (LH)","correct":false,"visible":false}]},{"id":3189,"text":"What do the alpha cells in islets of Langerhans secrete?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 427.","responses":[{"text":"Somatostatin","correct":false,"visible":false},{"text":"Glucagon","correct":true,"visible":false},{"text":"Insulin","correct":false,"visible":false},{"text":"Growth hormone","correct":false,"visible":false},{"text":"Ca²⁺ ions","correct":false,"visible":false}]},{"id":3202,"text":"Pheochromocytoma is a tumor of which of the following?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 172.","responses":[{"text":"Adrenal medulla","correct":true,"visible":false},{"text":"Hepatic origin","correct":false,"visible":false},{"text":"Hepatic origin","correct":false,"visible":false},{"text":"Vascular origin","correct":false,"visible":false},{"text":"Adrenal cortex","correct":false,"visible":false}]},{"id":3203,"text":"Obesity and a sedentary lifestyle are the known risk factors of diabetes mellitus. Both of these factors lead to which of the following?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 342.","responses":[{"text":"Decrease in beta cell function","correct":false,"visible":false},{"text":"Hyperglycemia","correct":false,"visible":false},{"text":"Insulin resistance","correct":true,"visible":false},{"text":"Impaired glucose tolerance","correct":false,"visible":false},{"text":"Hyperinsulinemia","correct":false,"visible":false}]},{"id":3204,"text":"Which of these is a characteristic clinical feature of hypothyroidism?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 162.","responses":[{"text":"Nervousness","correct":false,"visible":false},{"text":"Weight loss","correct":false,"visible":false},{"text":"Myxedema","correct":true,"visible":false},{"text":"Muscle weakness","correct":false,"visible":false},{"text":"Exophthalmos (protrusion of eyeball)","correct":false,"visible":false}]},{"id":3206,"text":"A 40-year-old woman comes to the outpatient department with the complaint of increased frequency of micturition and passing very large quantities of pale urine. She says that she is always thirsty. On radiography, a hypothalamic lesion is seen. The lesion is affecting which of the following nuclei?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 938.","responses":[{"text":"Posterior nucleus","correct":false,"visible":false},{"text":"Supraoptic nucleus","correct":true,"visible":false},{"text":"Suprachiasmatic nucleus","correct":false,"visible":false},{"text":"Paraventricular nucleus","correct":false,"visible":false},{"text":"Preoptic nucleus","correct":false,"visible":false}]},{"id":3209,"text":"A microscopic slide labeled as pancreas revealed the presence of ducts and islets of Langerhans. A duct lined by stratified columnar was also seen. Which type of pancreatic duct is lined by this epithelium?","explanation":"The duct lined by stratified columnar epithelium in the pancreas is the **large excretory duct**, also known as the **main pancreatic duct**. The main pancreatic duct is the largest duct in the pancreas and is responsible for carrying the exocrine secretions produced by the acinar cells to the duodenum, where they aid in digestion.\r\n\r\nThe pancreas has a complex system of ducts that transport the secretions produced by different types of cells. The secretions from the acinar cells, which contain digestive enzymes, flow into the intercalated ducts, then into the **intralobular ducts**, and finally into the interlobular ducts. These smaller ducts ultimately merge to form the main pancreatic duct.\r\n\r\nWhile the intercalated ducts and intralobular ducts are lined by simple cuboidal epithelium, the main pancreatic duct is lined by **stratified columnar epithelium**, which allows for more efficient transport of secretions due to its larger size and capacity.","reference":"Laiq Hussain Siddiqui. Medical Histology Text And Atlas. 6th ed. Paramount; 2019: 196.","responses":[{"text":"Large excretory duct","correct":true,"visible":false},{"text":"Intralobular duct","correct":false,"visible":false},{"text":"Intercalated duct","correct":false,"visible":false},{"text":"Interlobular duct","correct":false,"visible":false},{"text":"Striated duct","correct":false,"visible":false}]},{"id":3213,"text":"Which of the following is not involved in the regulation of hormone action on the target organ?","explanation":null,"reference":null,"responses":[{"text":"Hormone specific receptors","correct":false,"visible":false},{"text":"Rate of synthesis and secretion","correct":false,"visible":false},{"text":"Ultimate degradation","correct":false,"visible":false},{"text":"Availability of substrate","correct":false,"visible":false},{"text":"Specific transport system","correct":true,"visible":false}]},{"id":3214,"text":"Thyroiditis is the inflammation of the thyroid gland encompassing a number of disorders that have some elements of inflammation. Subacute thyroiditis is believed to be triggered by which of the following insults?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 163.","responses":[{"text":"Trauma","correct":false,"visible":false},{"text":"Fungal infection","correct":false,"visible":false},{"text":"Bacterial infection","correct":false,"visible":false},{"text":"Iodine deficiency","correct":false,"visible":false},{"text":"Viral infection","correct":true,"visible":false}]},{"id":3216,"text":"Insulin is released from vesicles of beta cells due to the opening of which channels?","explanation":"Insulin release from beta cells of the pancreas is triggered by the opening of **Ca2+ channels** in response to an increase in blood glucose levels. The process of insulin secretion involves a complex interplay of events known as the **glucose-induced insulin secretion pathway**.\r\n\r\nWhen blood glucose levels rise, glucose enters the beta cells through glucose transporters (GLUT2). The metabolism of glucose leads to the production of ATP. The increased ATP levels result in the closure of ATP-sensitive K+ channels (KATP channels), which causes the membrane potential to depolarize. This depolarization subsequently leads to the opening of voltage-gated Ca2+ channels.\r\n\r\nThe influx of Ca2+ into the beta cells triggers the exocytosis of insulin-containing vesicles (granules) and the release of insulin into the bloodstream. The elevated insulin levels facilitate the uptake of glucose by peripheral tissues, thereby reducing blood glucose levels.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 979.","responses":[{"text":"K+ channels","correct":false,"visible":false},{"text":"Aqua channels","correct":false,"visible":false},{"text":"Na+ channels","correct":false,"visible":false},{"text":"Ca+2 channels","correct":true,"visible":false},{"text":"Mg+2 channels","correct":false,"visible":false}]},{"id":3217,"text":"Which of the following cells are not present in the parenchyma of the parathyroid gland?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 430, 432-434.","responses":[{"text":"Oxyphil cells","correct":false,"visible":false},{"text":"C cells","correct":true,"visible":false},{"text":"Chief cells","correct":false,"visible":false},{"text":"Lymphocytes","correct":false,"visible":false},{"text":"Adipose cells","correct":false,"visible":false}]},{"id":3218,"text":"A slide having three distinct zones, is shown to a student. Each zone has a different arrangement of cells but cells of all three zones show an abundance of the smooth endoplasmic reticulum. The slide is from which of the following tissue?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 424.","responses":[{"text":"Lymph node","correct":false,"visible":false},{"text":"Thyroid gland","correct":false,"visible":false},{"text":"Parathyroid gland","correct":false,"visible":false},{"text":"Suprarenal gland","correct":true,"visible":false},{"text":"Pancreas","correct":false,"visible":false}]},{"id":3220,"text":"Which of the following activates adenylate cyclase?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 924.","responses":[{"text":"Insulin","correct":false,"visible":false},{"text":"Ca+2 ions","correct":false,"visible":false},{"text":"K+ ions","correct":false,"visible":false},{"text":"Glucagon","correct":true,"visible":false},{"text":"Prostaglandin E1","correct":false,"visible":false}]},{"id":3222,"text":"During the histological examination, a slide is prepared from a tissue that exhibits multiple spherical follicles. These follicles appear to be lined by tall columnar cells and their cavity is filled with glycoproteins. The slide is taken from which tissue?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 430.","responses":[{"text":"Suprarenal gland","correct":false,"visible":false},{"text":"Active stage of the thyroid gland","correct":true,"visible":false},{"text":"Parathyroid gland","correct":false,"visible":false},{"text":"Inactive stage of the thyroid gland","correct":false,"visible":false},{"text":"Cortex of the kidney","correct":false,"visible":false}]},{"id":3224,"text":"Which of the following decreases gluconeogenesis?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 976.","responses":[{"text":"Glucagon","correct":false,"visible":false},{"text":"Cortisol","correct":false,"visible":false},{"text":"Epinephrine","correct":false,"visible":false},{"text":"Glucocorticoids","correct":false,"visible":false},{"text":"Insulin","correct":true,"visible":false}]},{"id":3227,"text":"A person suffers from bitemporal hemianopia, which arose because of the compression of the optic nerve by the pituitary adenoma. Where is the pituitary gland present in relation to the optic chiasma?","explanation":null,"reference":"(1) Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 888.\r\n\r\n(2) Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 415.","responses":[{"text":"Anteriorly","correct":false,"visible":false},{"text":"Superiorly","correct":false,"visible":false},{"text":"Inferiorly","correct":true,"visible":false},{"text":"Lateraly","correct":false,"visible":false},{"text":"Posteriorly","correct":false,"visible":false}]},{"id":3230,"text":"Hyperparathyroidism leads to a decrease in plasma levels of which of these?","explanation":"Hyperparathyroidism leads to an increase in plasma levels of calcium (hypercalcemia) and a decrease in plasma levels of **phosphate** (hypophosphatemia).\r\n\r\nIn hyperparathyroidism, the excessive secretion of parathyroid hormone (PTH) from the parathyroid glands causes increased reabsorption of calcium from bones, increased absorption of calcium from the intestines, and decreased excretion of calcium by the kidneys. As a result, the calcium levels in the blood rise.\r\n\r\nAt the same time, PTH also affects the handling of phosphate in the kidneys, leading to increased excretion of phosphate in the urine. This results in a decrease in plasma levels of phosphate.","reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 165.","responses":[{"text":"Phosphate","correct":true,"visible":false},{"text":"Sodium","correct":false,"visible":false},{"text":"Calcium","correct":false,"visible":false},{"text":"Calcitonin","correct":false,"visible":false},{"text":"Potassium","correct":false,"visible":false}]},{"id":3231,"text":"A 34-year-old female comes to the outpatient department with uncontrolled hypertension. A computed tomography (CT) scan reveals bilateral enlargement of the suprarenal gland. What is the most probable cause?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1127-1128.","responses":[{"text":"Renal tumor","correct":false,"visible":false},{"text":"Hyperplasia of suprarenal medulla","correct":false,"visible":false},{"text":"Pheochromocytoma","correct":true,"visible":false},{"text":"Renal cyst","correct":false,"visible":false},{"text":"Hyperplasia of suprarenal cortex","correct":false,"visible":false}]},{"id":3232,"text":"Axon terminals in neurohypophysis store the hormones that are synthesized in the hypothalamus. Which of the following hormones is secreted by neurohypophysis?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 938.","responses":[{"text":"Adrenocorticotropic hormone (ACTH)","correct":false,"visible":false},{"text":"Follicle-stimulating hormone (FSH)","correct":false,"visible":false},{"text":"Prolactin","correct":false,"visible":false},{"text":"Luteinizing hormone (LH)","correct":false,"visible":false},{"text":"Antidiuretic hormone (ADH)","correct":true,"visible":false}]},{"id":3233,"text":"Which of the following stimulates growth hormone secretion?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 933.","responses":[{"text":"Aging","correct":false,"visible":false},{"text":"Increased blood glucose","correct":false,"visible":false},{"text":"Increased free fatty acid level in blood","correct":false,"visible":false},{"text":"Somatomedins","correct":false,"visible":false},{"text":"Deep sleep","correct":true,"visible":false}]},{"id":3234,"text":"A 35-year-old lady is diagnosed with autoimmune hypothyroidism. Her physician is concerned about thyroid autoantibodies. Which of the following is the most appropriate antibody to detect autoimmune thyroid disease?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 163.","responses":[{"text":"Antifollicular","correct":false,"visible":false},{"text":"Antinuclear","correct":false,"visible":false},{"text":"Antiperoxidase","correct":true,"visible":false},{"text":"Anticytoplasmic","correct":false,"visible":false},{"text":"Anti-membrane","correct":false,"visible":false}]},{"id":3236,"text":"Which is the most common site of thyroglossal cyst?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 1051.","responses":[{"text":"Near lower border of the body of the hyoid bone","correct":true,"visible":false},{"text":"Infront of trachea","correct":false,"visible":false},{"text":"Base of tongue","correct":false,"visible":false},{"text":"Near laryngeal cartilages","correct":false,"visible":false},{"text":"Near the lower border of mandible","correct":false,"visible":false}]},{"id":3238,"text":"What does pheochromocytoma, a rare tumor, secrete?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 172-173.","responses":[{"text":"Tyrosinase","correct":false,"visible":false},{"text":"Androgen","correct":false,"visible":false},{"text":"Insulin","correct":false,"visible":false},{"text":"Oxytocin","correct":false,"visible":false},{"text":"Catecholamines","correct":true,"visible":false}]},{"id":3239,"text":"Which of the following hormone is derived from the amino acid tyrosine?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 405-406.","responses":[{"text":"Testosterone","correct":false,"visible":false},{"text":"Estrogen","correct":false,"visible":false},{"text":"Progesterone","correct":false,"visible":false},{"text":"Growth hormone","correct":false,"visible":false},{"text":"Thyroid hormone","correct":true,"visible":false}]},{"id":3242,"text":"What is the general metabolic effect of glucocorticoids?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 962-964.","responses":[{"text":"Anti-insulin effect, catabolic in the periphery and anabolic in the liver","correct":true,"visible":false},{"text":"Enhances energy provision","correct":false,"visible":false},{"text":"Causes the synthesis of significant proteins","correct":false,"visible":false},{"text":"Insulin function enhancement","correct":false,"visible":false},{"text":"Excessive catabolism of proteins, fats, and carbohydrates","correct":false,"visible":false}]},{"id":3244,"text":"Which one of the following is a characteristic sign of hyperthyroidism?","explanation":null,"reference":"(1) Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 346.\r\n\r\n(2) Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1076.","responses":[{"text":"Bradycardia","correct":false,"visible":false},{"text":"Slow reflexes","correct":false,"visible":false},{"text":"Jerky reflexes","correct":false,"visible":false},{"text":"Fine muscle tremor","correct":true,"visible":false},{"text":"Coarse tremor of muscles","correct":false,"visible":false}]},{"id":3246,"text":"What is the major target of glucagon for its action?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 982.","responses":[{"text":"Liver","correct":true,"visible":false},{"text":"Brain","correct":false,"visible":false},{"text":"Kidney","correct":false,"visible":false},{"text":"Skeletal muscle","correct":false,"visible":false},{"text":"Adipose tissue","correct":false,"visible":false}]},{"id":3247,"text":"Which hormone acts mainly on the genetic machinery of the cell?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 925.","responses":[{"text":"Follicle-stimulating hormone","correct":false,"visible":false},{"text":"Adrenaline","correct":false,"visible":false},{"text":"Glucagon","correct":false,"visible":false},{"text":"Aldosterone","correct":true,"visible":false},{"text":"Insulin","correct":false,"visible":false}]},{"id":3250,"text":"What function do the hormones produced by the thyroid gland have?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 944-945.","responses":[{"text":"Body growth","correct":true,"visible":false},{"text":"Glandular development","correct":false,"visible":false},{"text":"Breast development","correct":false,"visible":false},{"text":"Blood pressure","correct":false,"visible":false},{"text":"Uterine muscle contraction","correct":false,"visible":false}]},{"id":3255,"text":"During a histological examination, a student observes a slide showing a group of secretory cells with fenestrated capillaries. On further examination, cells appear to be of four different types. The slide is taken from which of the following?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 427.","responses":[{"text":"Follicles of thyroid","correct":false,"visible":false},{"text":"Head of pancreas","correct":false,"visible":false},{"text":"Medulla of adrenal gland","correct":false,"visible":false},{"text":"Tail of pancreas","correct":true,"visible":false},{"text":"Sinusoids of liver","correct":false,"visible":false}]},{"id":3262,"text":"Which of the following is true regarding the lab diagnosis of hyperthyroidism?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1077.","responses":[{"text":"Thyroid stimulating hormone (TSH) levels increased","correct":false,"visible":false},{"text":"Parathyroid hormone levels decreased","correct":false,"visible":false},{"text":"Parathyroid hormone levels increased","correct":false,"visible":false},{"text":"Free T3 and T4 levels decreased","correct":false,"visible":false},{"text":"Thyroid stimulating hormone (TSH) levels decreased","correct":true,"visible":false}]},{"id":3263,"text":"Which of the following is a function of the parathyroid hormone?","explanation":null,"reference":"(1) Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 1000.\r\n\r\n(2) Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 338.","responses":[{"text":"Decreases renal phosphate excretion","correct":false,"visible":false},{"text":"Decreases intestinal absorption of calcium","correct":false,"visible":false},{"text":"Decreases the blood calcium level","correct":false,"visible":false},{"text":"Increases osteoclastic resorption of bone","correct":true,"visible":false},{"text":"Increases renal calcium excretion","correct":false,"visible":false}]},{"id":3265,"text":"What is the primary source of energy for the brain?","explanation":null,"reference":"Mergenthaler P, Lindauer U, Dienel GA, Meisel A. Sugar for the brain: the role of glucose in physiological and pathological brain function. Trends in neurosciences. Published October 2013. Accessed June 23, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3900881/","responses":[{"text":"Glucose","correct":true,"visible":false},{"text":"Fatty acids","correct":false,"visible":false},{"text":"Glutamine","correct":false,"visible":false},{"text":"Creatine","correct":false,"visible":false},{"text":"Alanine","correct":false,"visible":false}]},{"id":3267,"text":"One major clinical manifestation of hypoparathyroidism is tetany which is a hallmark of which of these?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 1004.","responses":[{"text":"Parathyroid hyperplasia","correct":false,"visible":false},{"text":"Hypocalcemia","correct":true,"visible":false},{"text":"Vitamin D deficiency","correct":false,"visible":false},{"text":"Hyperkalemia","correct":false,"visible":false},{"text":"Neuropathy","correct":false,"visible":false}]},{"id":3269,"text":"The histological section of neurohypophysis shows supporting cells and axons with dilated terminal ends. What are the supporting cells and dilated terminal ends of axons called?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 421.","responses":[{"text":"Mammophytes and herring body","correct":false,"visible":false},{"text":"Neurophysin and herring body","correct":false,"visible":false},{"text":"Neurohypophysis and pars nervosa","correct":false,"visible":false},{"text":"Vasopressin and oxytocin bodies","correct":false,"visible":false},{"text":"Pituicytes and herring body","correct":true,"visible":false}]},{"id":3270,"text":"Which hormone causes milk ejection during suckling?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 940.","responses":[{"text":"Oxytocin","correct":true,"visible":false},{"text":"Prolactin","correct":false,"visible":false},{"text":"Progesterone","correct":false,"visible":false},{"text":"Luteinizing hormone (LH)","correct":false,"visible":false},{"text":"Somatomammotroph","correct":false,"visible":false}]},{"id":3409,"text":"A patient presents with swelling in his right leg and edema. He is diagnosed with Hashimoto thyroiditis. Which of the following is true for the reason behind fluid accumulation in his leg?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 639-640.","responses":[{"text":"Increase in hyaluronic acid","correct":true,"visible":false},{"text":"Increase in acetic acid","correct":false,"visible":false},{"text":"Hives","correct":false,"visible":false},{"text":"Abscess","correct":false,"visible":false},{"text":"Hyperglycemia","correct":false,"visible":false}]},{"id":3410,"text":"The pancreas is referred to as a compound tubuloacinar gland. Which of the following best describes the word \"compound\"?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 86.","responses":[{"text":"Interlobular ducts","correct":false,"visible":false},{"text":"All of them","correct":false,"visible":false},{"text":"Branched secretory portion","correct":false,"visible":false},{"text":"Branched duct","correct":true,"visible":false},{"text":"Exocrine and endocrine parts","correct":false,"visible":false}]},{"id":3411,"text":"Hyperactivity of which of the following endocrine gland increases cortisol secretion?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 917.","responses":[{"text":"Parathyroid gland","correct":false,"visible":false},{"text":"Pancreas","correct":false,"visible":false},{"text":"Pineal gland","correct":false,"visible":false},{"text":"Posterior pituitary gland","correct":false,"visible":false},{"text":"Anterior pituitary gland","correct":true,"visible":false}]},{"id":3412,"text":"In diabetes mellitus gangrene of the lower extremity is caused by which of the following?","explanation":null,"reference":null,"responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Microvascular disease","correct":false,"visible":false},{"text":"Macrovascular disease","correct":true,"visible":false},{"text":"Skin disease","correct":false,"visible":false},{"text":"Trauma","correct":false,"visible":false}]},{"id":3413,"text":"The adrenal cortex is embryologically derived from which of the following?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 75.","responses":[{"text":"Epiblast cells","correct":false,"visible":false},{"text":"Mesoderm","correct":true,"visible":false},{"text":"Neural crest cells","correct":false,"visible":false},{"text":"Endoderm","correct":false,"visible":false},{"text":"Surface ectoderm","correct":false,"visible":false}]},{"id":3414,"text":"Which of the following is an intermediate-acting insulin?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 755.","responses":[{"text":"Insulin lispro","correct":false,"visible":false},{"text":"Protamine zinc","correct":false,"visible":false},{"text":"Regular insulin","correct":false,"visible":false},{"text":"Neutral protamine hagedorn (NPH)","correct":true,"visible":false},{"text":"Insulin aspartate","correct":false,"visible":false}]},{"id":3418,"text":"A diabetes mellitus patient wants to drink insulin instead of using the injection to avoid pain. Which of the following would be true as an after effect?","explanation":null,"reference":"Kumar V, Choudhry I, Namdev A, et al. Oral insulin: myth or reality. Current Diabetes Reviews. Published 2018. Accessed June 23, 2022. https://pubmed.ncbi.nlm.nih.gov/28637407/","responses":[{"text":"Persistent hyperglycemia","correct":true,"visible":false},{"text":"Diarrhea","correct":false,"visible":false},{"text":"Transient Ischemic attack","correct":false,"visible":false},{"text":"Uremia","correct":false,"visible":false},{"text":"Nausea","correct":false,"visible":false}]},{"id":3420,"text":"A histologist observes a gland under a microscope having two zones. The outermost layer is developed from which of the following?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 75, 259.","responses":[{"text":"Neural crest cells","correct":false,"visible":false},{"text":"Mesenchyme","correct":true,"visible":false},{"text":"Epiblast cells","correct":false,"visible":false},{"text":"Intermediate mesoderm","correct":false,"visible":false},{"text":"Ectoderm","correct":false,"visible":false}]},{"id":3421,"text":"At what value of glucose concetration does insulin secretion rises rapidly?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 980.","responses":[{"text":"200 mg/dL","correct":false,"visible":false},{"text":"150 mg/dL","correct":false,"visible":false},{"text":"50 mg/dL","correct":false,"visible":false},{"text":"500 mg/dL","correct":false,"visible":false},{"text":"100 mg/dL","correct":true,"visible":false}]},{"id":3426,"text":"A boy was brought to the outpatient department with a swelling anterior to sternocleidomastoid muscle at the lower one-third of the neck. Which of the following could be the likely pathology?","explanation":null,"reference":null,"responses":[{"text":"Piriform fistula","correct":false,"visible":false},{"text":"External cervical sinus","correct":false,"visible":false},{"text":"Cervical fistula","correct":false,"visible":false},{"text":"Cervical cyst","correct":true,"visible":false},{"text":"Internal cervical sinus","correct":false,"visible":false}]},{"id":3427,"text":"Glucagon is not responsible for which of the following?","explanation":null,"reference":"(1) Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 100.\r\n\r\n\r\n(2) Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 339.","responses":[{"text":"Increased glycolysis","correct":true,"visible":false},{"text":"Increased gluconeogenesis","correct":false,"visible":false},{"text":"Increased ketogenesis","correct":false,"visible":false},{"text":"Increased lipolysis","correct":false,"visible":false},{"text":"Increased glycogenolysis","correct":false,"visible":false}]},{"id":3428,"text":"Which of the following is correct about the pancreatic duct?","explanation":"The pancreatic duct, also known as the duct of Wirsung, is a major duct of the pancreas responsible for carrying digestive enzymes and bicarbonate from the pancreas to the duodenum. It begins at the **tail of the pancreas** and runs longitudinally through the pancreas, collecting tributaries from smaller ducts along its course.\r\n\r\nNear the head of the pancreas, the main pancreatic duct usually merges with the common bile duct, forming the hepatopancreatic ampulla (Ampulla of Vater). The ampulla then opens into the duodenum at the major duodenal papilla, which is located on the medial wall of the second part of the duodenum.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 489.","responses":[{"text":"Starts from the neck of pancreas","correct":false,"visible":false},{"text":"Starts from the tail of pancreas","correct":true,"visible":false},{"text":"Starts from head and neck of pancreas","correct":false,"visible":false},{"text":"Starts from the head of pancreas","correct":false,"visible":false},{"text":"Opens in duodenum at minor duodenal papilla","correct":false,"visible":false}]},{"id":3429,"text":"The very first step of thyroid hormone synthesis is 'iodine trapping'. What does this mean?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 942.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Concentrating iodide in circulation","correct":false,"visible":false},{"text":"Increased absorption of iodide from intestine","correct":false,"visible":false},{"text":"Concentrating iodide with chloride in thyroid cells","correct":false,"visible":false},{"text":"Concentrating iodide in thyroid gland","correct":true,"visible":false}]},{"id":3430,"text":"Which of the following secretes androgens?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 956.","responses":[{"text":"All of these","correct":false,"visible":false},{"text":"Zona fasciculata","correct":false,"visible":false},{"text":"Adrenal medulla","correct":false,"visible":false},{"text":"Zona glomerulosa","correct":false,"visible":false},{"text":"Zona reticularis","correct":true,"visible":false}]},{"id":3443,"text":"Which of the following is the most common etiology of hypothyroidism?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 163.","responses":[{"text":"Anti-thyroid peroxidase antibodies","correct":true,"visible":false},{"text":"Anti-TSH receptor antibodies","correct":false,"visible":false},{"text":"Anti-thyroglobulin antibodies","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Radioactive thyroid scan","correct":false,"visible":false}]},{"id":3448,"text":"What are the hormones produced by the adrenal medulla derived from?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 285.","responses":[{"text":"Tyrosine","correct":true,"visible":false},{"text":"Phenylalanine","correct":false,"visible":false},{"text":"Valine","correct":false,"visible":false},{"text":"Tryptophan","correct":false,"visible":false},{"text":"Arginine","correct":false,"visible":false}]},{"id":3449,"text":"Which of the following glands begins to develop on the 24th day?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 168.","responses":[{"text":"Adrenal gland","correct":false,"visible":false},{"text":"Pituitary gland","correct":false,"visible":false},{"text":"Thyroid gland","correct":true,"visible":false},{"text":"Pancreas","correct":false,"visible":false},{"text":"Parathyroid gland","correct":false,"visible":false}]},{"id":3450,"text":"Which of the following is the most common cause of Cushing's syndrome?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1115.","responses":[{"text":"Iatrogenic cause","correct":false,"visible":false},{"text":"Pituitary adenoma","correct":false,"visible":false},{"text":"Adrenal carcinoma","correct":false,"visible":false},{"text":"Glucocorticoid therapy","correct":true,"visible":false},{"text":"Adrenal cortex adenoma","correct":false,"visible":false}]},{"id":3451,"text":"Gigantism is due to hypersecretion of which of the following cells?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1071.","responses":[{"text":"Somatotrophs","correct":true,"visible":false},{"text":"Thyrotrophs","correct":false,"visible":false},{"text":"Lactotrophs","correct":false,"visible":false},{"text":"Gonadotrophs","correct":false,"visible":false},{"text":"Corticotrophs","correct":false,"visible":false}]},{"id":3452,"text":"An 18-year-old female presents with weight gain, thinning of hair, low pulse and blood pressure, cold intolerance, clammy skin that is cold, constipation, and difficulty to concentrate. What would be the most probable diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Hyperparathyroidism","correct":false,"visible":false},{"text":"Cushing syndrome","correct":false,"visible":false},{"text":"Hypothyroidism","correct":true,"visible":false},{"text":"Hyperthyroidism","correct":false,"visible":false},{"text":"Hypoparathyroidism","correct":false,"visible":false}]},{"id":3453,"text":"Which of the following does Rathke's pouch form?","explanation":null,"reference":"Sadler TW. Langman’s Medical Embryology. 14th ed. Wolters Kluwer; 2018: 331.","responses":[{"text":"Inferior lobe","correct":false,"visible":false},{"text":"Posterior pituitary lobe","correct":false,"visible":false},{"text":"Anterior pituitary lobe","correct":true,"visible":false},{"text":"Intermediate pituitary lobe","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":3461,"text":"A newborn was diagnosed with multiple congenital anomalies and was having seizures right after it was born with a glucose level of 19 mg/dl. What would be the disease the mother is suffering from to cause these defects in the child?","explanation":"The most likely disease the mother is suffering from, which could cause multiple congenital anomalies and low glucose levels in the newborn, is **gestational diabetes**.\r\n\r\nGestational diabetes is a type of diabetes that develops during pregnancy. It occurs when the mother's body cannot produce enough insulin to regulate blood sugar effectively. High blood sugar levels in the mother can cross the placenta and affect the developing fetus, leading to various congenital anomalies.\r\n\r\nIn this case, the mother's elevated blood sugar levels may have resulted in impaired fetal development, leading to the multiple congenital anomalies observed in the newborn. Additionally, the baby's pancreas would have been exposed to high levels of glucose during gestation, causing an increased insulin response. After birth, when the baby is no longer receiving glucose from the mother, this exaggerated insulin response could result in hypoglycemia, as evidenced by the low glucose level of 19 mg/dl and the occurrence of seizures.","reference":"(1) Abramowski A, Ward R, Hamdan AH. Neonatal hypoglycemia. In: StatPearls. StatPearls Publishing; 2022. Accessed June 23, 2022. http://www.ncbi.nlm.nih.gov/books/NBK537105/\r\n\r\n\r\n(2) Şimşek DG, Ecevit A, Hatipoğlu N, et al. Neonatal Hyperglycemia, which threshold value, diagnostic approach and treatment?: Turkish Neonatal and Pediatric Endocrinology and Diabetes Societies consensus report. Turkish Archives of Pediatrics/Türk Pediatri Arşivi. Published December 25, 2018. Accessed June 23, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6568286/","responses":[{"text":"Diabetes of the young","correct":false,"visible":false},{"text":"Adrenal carcinoma","correct":false,"visible":false},{"text":"Pancreatic endocrine tumor","correct":false,"visible":false},{"text":"Gestational diabetes","correct":true,"visible":false},{"text":"Diabetes mellitus type 2","correct":false,"visible":false}]},{"id":3462,"text":"A lady was taking oral glucocorticoids as per her doctor's recommendation. After that, she went for surgery due to a hip fracture. Which of the following would be a cause of bone fracture?","explanation":null,"reference":null,"responses":[{"text":"None of them","correct":false,"visible":false},{"text":"Resorption of calcium from bone","correct":true,"visible":false},{"text":"Osteoarthritis","correct":false,"visible":false},{"text":"Osteochondroma","correct":false,"visible":false},{"text":"Decreased bone formation","correct":false,"visible":false}]},{"id":3463,"text":"Which of the following is the most appropriate investigation for long-term monitoring of glucose levels?","explanation":null,"reference":null,"responses":[{"text":"Random blood glucose","correct":false,"visible":false},{"text":"Oral glucose tolerance","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Fasting blood glucose","correct":false,"visible":false},{"text":"HBA1c","correct":true,"visible":false}]},{"id":3465,"text":"Which of the following is the most sensitive marker for the diagnosis of hypothyroidism?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1078.","responses":[{"text":"T3","correct":false,"visible":false},{"text":"T4","correct":false,"visible":false},{"text":"Free T3","correct":false,"visible":false},{"text":"ACTH","correct":false,"visible":false},{"text":"TSH","correct":true,"visible":false}]},{"id":3466,"text":"A man presents with enlarged hands and is diagnosed with acromegaly. Which of the following was used to confirm the diagnosis?","explanation":null,"reference":null,"responses":[{"text":"IGF-1 level","correct":false,"visible":false},{"text":"GH levels","correct":false,"visible":false},{"text":"Oral glucose test","correct":true,"visible":false},{"text":"ACTH levels","correct":false,"visible":false},{"text":"All of these","correct":false,"visible":false}]},{"id":3468,"text":"Which of the following is true about a slide showing numerous cells mostly in the center and four different types of cells are observed?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 427, 429.","responses":[{"text":"Alpha cells","correct":false,"visible":false},{"text":"P cells","correct":false,"visible":false},{"text":"C cells","correct":false,"visible":false},{"text":"Delta cells","correct":false,"visible":false},{"text":"Beta cells","correct":true,"visible":false}]},{"id":3469,"text":"Which of the following hormones is released from alpha cells?","explanation":null,"reference":null,"responses":[{"text":"Insulin","correct":false,"visible":false},{"text":"Glucagon","correct":true,"visible":false},{"text":"Pancreatic Polypeptide","correct":false,"visible":false},{"text":"Somatostatin","correct":false,"visible":false},{"text":"Aldosterone","correct":false,"visible":false}]},{"id":3470,"text":"Which of the following is true about the action of somatostatin?","explanation":null,"reference":null,"responses":[{"text":"All of them","correct":false,"visible":false},{"text":"Decreases glucagon","correct":false,"visible":false},{"text":"Decreases insulin","correct":false,"visible":false},{"text":"Decreases glucagon and insulin secretion","correct":true,"visible":false},{"text":"Increases Insulin","correct":false,"visible":false}]},{"id":3471,"text":"Which of the following is true about the action of growth hormone?","explanation":null,"reference":null,"responses":[{"text":"Decreases lipolysis","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"It promotes formation of somatomedins by liver","correct":true,"visible":false},{"text":"Promotes synthesis of somatostatins","correct":false,"visible":false},{"text":"Increases lipogenesis","correct":false,"visible":false}]},{"id":3473,"text":"Which of the following is an indication for vasopressin?","explanation":null,"reference":null,"responses":[{"text":"Cushing syndrome","correct":false,"visible":false},{"text":"Diabetes mellitus","correct":false,"visible":false},{"text":"Adrenal carcinoma","correct":false,"visible":false},{"text":"Hypertension","correct":false,"visible":false},{"text":"Diabetes insipidus","correct":true,"visible":false}]},{"id":3474,"text":"Which of the following is one of the major problems in diabetes mellitus?","explanation":null,"reference":null,"responses":[{"text":"Decreased lipolysis","correct":false,"visible":false},{"text":"Decreased ketogenesis","correct":false,"visible":false},{"text":"Increased gluconeogenesis","correct":true,"visible":false},{"text":"Increased lipogenesis","correct":false,"visible":false},{"text":"Decreased gluconeogenesis","correct":false,"visible":false}]},{"id":8262,"text":"A 30-year-old woman presents to the clinic with palpitations, weight loss, and excessive sweating for almost 5-6 months. She cannot concentrate on carrying out her daily activities especially looking after her children. Recently, she also developed pain in both eyes and her friend told her that one of her eyes has become more prominent than the other. What is the most likely cause of her condition?","explanation":"The patient's symptoms, including palpitations, weight loss, excessive sweating, inability to concentrate, and prominent eyes, are characteristic of **hyperthyroidism**. Grave's disease is an autoimmune disorder where the immune system produces antibodies that stimulate the thyroid gland to produce excessive amounts of thyroid hormones.\r\n\r\nCommon clinical features of Grave's disease include:\r\n\r\n1. **Palpitations**: Due to an increased heart rate and cardiac output caused by elevated thyroid hormones.\r\n\r\n2. **Weight loss**: Hyperthyroidism increases metabolic rate, leading to unintended weight loss.\r\n\r\n3. **Excessive sweating**: Hyperthyroidism increases sympathetic nervous system activity, leading to increased sweating.\r\n\r\n4. **Inability to concentrate**: Excessive thyroid hormones can affect mental function and cause difficulty in focusing.\r\n\r\n5. **Prominent eyes (exophthalmos)**: Grave's disease can lead to swelling of the tissues behind the eyes, causing the eyes to bulge forward.\r\n\r\nThe combination of these symptoms strongly suggests Grave's disease as the underlying cause of her condition.","reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1081-1082.","responses":[{"text":"Generalized anxiety disorder","correct":false,"visible":false},{"text":"Hashimoto’s thyroiditis","correct":false,"visible":false},{"text":"Grave’s disease","correct":true,"visible":false},{"text":"Hyperthyroidism","correct":false,"visible":false},{"text":"Toxic nodular goiter","correct":false,"visible":false}]},{"id":10823,"text":"A 30-year-old man is referred to the clinic for evaluation of visual field defects. Additional complaints include fatigue, myalgia, headache, bilateral knee pain, and excessive perspiration. His blood pressure is 156/94 mm Hg, pulse 56/ minute, weight 105 kg, and height 6 feet 2 inches. His hands are thick and enlarged; his calcaneus could not be felt through his heel pad. Laboratory studies are as follows: free thryoxine index 3.6 mcg/dL (4-11 mcg/dL), TSH 0.7 U/L, testosterone 87 ng/dL (300 - 1000 ng/dL), LH 3.2 mIU/mL (2 - 28 mIU/mL), prolactin 5 ng/dL (\u003c 8 ng/dL), 8 am cortisol 2 mcg/dL (6-24 mcg/dL), and fasting glucose 186 mg/dL. Which of the following diagnoses best explains the patient's signs and symptoms?","explanation":null,"reference":"Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022: 685-686.","responses":[{"text":"Acromegaly","correct":true,"visible":false},{"text":"Secondary hyperthyrodism","correct":false,"visible":false},{"text":"Secondary hypogonadism","correct":false,"visible":false},{"text":"Hyperpituitarism","correct":false,"visible":false}]},{"id":10824,"text":"A 25-year-old woman admitted to the hospital for the treatment of thyrotoxicosis suddenly becomes severely dyspneic. Her vitals are as follows: blood pressure 60/40 mm Hg, heart rate 180/minute with irregularly regular pulse, and cold peripheries. ECG reveals fast atrial fibrillation; her ECG done one day earlier had only revealed tachycardia. Chest x-ray reveals frank pulmonary edema. Which of the following is the most appropriate treatment?","explanation":null,"reference":"Davidson's principles and practice of medicine 23rd edition, pg. 472","responses":[{"text":"Carotid massage","correct":false,"visible":false},{"text":"Intravenous furosemide and intravenous amiodarone","correct":false,"visible":false},{"text":"Intravenous verapamil","correct":false,"visible":false},{"text":"Intravenous furosemide","correct":false,"visible":false},{"text":"DC cardioversion","correct":true,"visible":false}]},{"id":10860,"text":"A 42-year-old woman comes to the clinic for evaluation of uncontrolled blood sugar. She has a history of type 2 diabetes mellitus and takes glimepiride 20 mg every day before breakfast. Her BMI is 32 kg/m2 and HbA1c is 8.4%. Which of the following is the best treatment option for this patient?","explanation":null,"reference":"Davidson's principles and practice of medicine 24th edition, pg. 734","responses":[{"text":"Stop glimepiride and start insulin","correct":false,"visible":false},{"text":"Add an DPP-4 inhibitor and follow life-style modification","correct":false,"visible":false},{"text":"Increase the dose of glimepiride","correct":false,"visible":false},{"text":"Add on metformin and strictly follow life-style modification","correct":true,"visible":false},{"text":"Add on thiazolidinone and strictly follow lifestyle modification","correct":false,"visible":false}]},{"id":10862,"text":"A 20-year-old man is referred to the diabetes clinic with newly diagnosed diabetes (fasting glucose on two occasions \u003e289 mg/dL). He has had osmotic symptoms (polyuria and polydipsia) for 6 months, and his weight has recently increased by around 14 kg. On examination, there are purplish striae on the abdomen with central obesity. Which of the following is the most likely diagnosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1115-1118.","responses":[{"text":"Primary hypothyroidism","correct":false,"visible":false},{"text":"Acromegaly","correct":false,"visible":false},{"text":"Type 2 diabetes with metabolic syndrome","correct":false,"visible":false},{"text":"Cushing syndrome","correct":true,"visible":false},{"text":"Lipodystrophy","correct":false,"visible":false}]},{"id":10885,"text":"A 16-year-old boy has type 1 diabetes mellitus and is on mixed insulin twice daily. His HbA1c is 9.5%. Which of the following is the best next step in management?","explanation":null,"reference":"Kumar and Clarke’s 10th ed pg 714","responses":[{"text":"Put him on sliding scale of insulin","correct":false,"visible":false},{"text":"Put him on basal bolus regimen","correct":true,"visible":false},{"text":"Add on metformin","correct":false,"visible":false},{"text":"Increase the current dosage of insulin","correct":false,"visible":false},{"text":"Put him on split dosage of insulin twice thrice daily","correct":false,"visible":false}]},{"id":10890,"text":"A 24-year-old man presents to the clinic for evaluation of primary infertility. His semen analysis on two separate occasions shows severely abnormal spermatogenesis. Which of the following is the cause of this abnormality?","explanation":null,"reference":"Davidson's principles and practice of medicine 24th edition, pg. 671","responses":[{"text":"Pervious sexually transmitted infection","correct":false,"visible":false},{"text":"Hypogonadotrophic hypogonadism","correct":false,"visible":false},{"text":"Y chromosome microdeletions","correct":true,"visible":false},{"text":"Varicocele","correct":false,"visible":false},{"text":"Hypergonadotrophic hypogonadism","correct":false,"visible":false}]},{"id":11006,"text":"A patient who is taking antithyroid drugs for hyperthyroidism develops sore throat and fever. Her total leukocyte count is low. Which of the following drugs is she most likely taking?","explanation":null,"reference":"Davidson's principles and practice of medicine, 24th edition, pg. 644","responses":[{"text":"Radioactive iodine","correct":false,"visible":false},{"text":"Methimazole","correct":true,"visible":false},{"text":"Propranolol","correct":false,"visible":false},{"text":"Digoxin","correct":false,"visible":false},{"text":"Nadolol","correct":false,"visible":false}]},{"id":11013,"text":"A 12-year-old boy is found in a closed room with increased salivation from the mouth and sweating profusely. His pulse is 50 beats/minute and blood pressure is 100/60 mm Hg. Which of the following is the most appropriate antidote?","explanation":null,"reference":"Davidson's principles and practice of medicine, 24th edition, pg. 233","responses":[{"text":"Vitamin K","correct":false,"visible":false},{"text":"Pralidoxime","correct":true,"visible":false},{"text":"Flumezanil","correct":false,"visible":false},{"text":"Warfarin","correct":false,"visible":false},{"text":"Propranolol","correct":false,"visible":false}]},{"id":13774,"text":"A 40-year-old female checked her own random blood glucose level using a glucometer in the mid-afternoon and it was 186 mg/dl (reference range \u003c140). She is currently asymptomatic and reports no excessive urination or thirst. Her medical history is unremarkable. Her mother has a 15-year history of type 2 diabetes mellitus, with onset at age 49. On physical examination, the patient's height is 164 cm, weight is 73.5 kg, and BMI is 27.3. Her heart rate is 82 beats/minute and her blood pressure is 128/82 mmHg. Velvety hyperpigmentation is noted on the posterior folds of her neck. The next morning, the patient presents after 8 hours of fasting and laboratory testing yields the following result: fasting plasma glucose - 94 mg/dl, and plasma glucose 2 hours after an oral load of 75 gm of glucose - 177 mg/dl. Which of the following is the correct interpretation of this patient's blood test results?","explanation":null,"reference":"Davidson's principles and practices of medicine 23rd edition, pg. 726, table 20.2","responses":[{"text":"Autoantibody testing is indicated before making a diagnosis","correct":false,"visible":false},{"text":"At least one of the tests should be repeated on another day before making a diagnosis","correct":false,"visible":false},{"text":"The patient can be diagnosed with impaired glucose tolerance; no additional testing is needed","correct":true,"visible":false},{"text":"The patient can be considered to have a normal glucose profile; no additional testing is needed","correct":false,"visible":false},{"text":"The glucose tests should be repeated after 12 hours of fasting","correct":false,"visible":false}]},{"id":13837,"text":"A 60-year-old female presents to the clinic with complaints of pins and needles sensation along with burning feet over the last 8 to 9 months. She is a known case of diabetes and has been non-compliant with oral hypoglycemic therapy for the last 15 years. Clinical examination reveals sensory loss in a stocking pattern, absent ankle jerks, and subtle weakness of dorsiflexion of the toes. Which of the following is the dominant type of neuropathy in this patient?","explanation":null,"reference":"Davidson's principles and practice of medicine 23rd edition, pg. 758-759","responses":[{"text":"Small fiber neuropathy","correct":false,"visible":false},{"text":"Mononeuropathy multiplex","correct":false,"visible":false},{"text":"Entrapment neuropathy","correct":false,"visible":false},{"text":"Distal symmetric neuropathy","correct":true,"visible":false},{"text":"Amyotrophic neuropathy","correct":false,"visible":false}]},{"id":14099,"text":"A 36-year-old female presents to the clinic with complaints of secondary amenorrhea and headache for 6 months. She has 3 children, the last-born is 2 years old. She started oral contraceptives after the birth of her last born, but stopped 11 months ago. She has also noted weight gain during the same time period. On examination, Ferriman-Gallwey score is 8/32, secondary sexual characteristics are well developed and there is no galactorrhea. However, visual confrontation shows left inferior temporal field defects. Serum thyroid-stimulating hormone (TSH) is 2.4 (0.4-4.0), luteinizing hormone (LH) is 0.2 (1.2-4.0), follicular stimulating hormone (FSH) is 2.0 (2.0-8.0) and prolactin levels are 90 (10-23). What is the most likely cause of her presentation?","explanation":null,"reference":"Davidson's principles and practice of medicine 24th edition, pg. 695 - 697","responses":[{"text":"Lactational amenorrhea","correct":false,"visible":false},{"text":"Prolactinoma","correct":true,"visible":false},{"text":"Secondary hypogonadism","correct":false,"visible":false},{"text":"Polycystic ovary syndrome","correct":false,"visible":false},{"text":"Hypothyroidism","correct":false,"visible":false}]},{"id":14102,"text":"A 31-year-old female presents to the medical outpatient department with complaints of amenorrhea for the past six months along with dyspareunia and bone pain all over the body. Investigations reveal negative urine pregnancy test, high concentrations of luteinizing hormone (LH) and follicle-stimulating hormone (FSH) along with low or low-normal estradiol. Which of the following is the most likely cause of amenorrhea in this patient?","explanation":null,"reference":"Davidson's principles and practice of medicine 24th edition, pg. 670","responses":[{"text":"Polycystic ovary syndrome","correct":false,"visible":false},{"text":"Hypergonadotrophic hypogonadism","correct":false,"visible":false},{"text":"Androgen secreting tumor","correct":false,"visible":false},{"text":"Premature ovarian failure/menopause","correct":true,"visible":false},{"text":"Pregnancy","correct":false,"visible":false}]},{"id":14104,"text":"A 35-year-old woman presents to the clinic with complaints of lethargy, palpitations, and weakness. She has had a profound weight loss of 12 Kg over the last 4 months. On examination, there are tremors of the hands and sweaty palms. Her eyes have a constant stare and she looks very frightened. There is a diffuse, firm goiter that moves with deglutition. Her thyroid function tests are as follows: thyroid stimulating hormone (TSH) - \u003c0.001 (0.4-4.0), total T4 - 20.9 (5.0-11.2), free T4 - 1.9 (0.86-1.76). Which of the following is the most likely cause of her condition?","explanation":null,"reference":"Davidson's principles and practice of medicine 24th edition, pg. 652 - 654","responses":[{"text":"Grave's disease","correct":true,"visible":false},{"text":"Subacute thyroiditis","correct":false,"visible":false},{"text":"Factitious thyroiditis","correct":false,"visible":false},{"text":"Toxic multinodular goiter","correct":false,"visible":false},{"text":"Hyperthyroid phase of Hashimoto's thyroiditis","correct":false,"visible":false}]},{"id":14155,"text":"Which of the following is a feature of atropine overdose?","explanation":null,"reference":"First Aid 2022, pg. 242","responses":[{"text":"Excessive urination","correct":false,"visible":false},{"text":"Dry skin and mucus membrane","correct":true,"visible":false},{"text":"Sinus bradycardia","correct":false,"visible":false},{"text":"Miosis","correct":false,"visible":false},{"text":"Diarrhea","correct":false,"visible":false}]},{"id":14169,"text":"A 20-year-old female presents to the outpatient department to be evaluated for short stature. Her history is significant for psychological problems, reduced IQ, altered bowel habits, and primary amenorrhea. Which of the following is the most likely cause of her short stature and clinical features?","explanation":null,"reference":"Davidson's principles and practice of medicine, 24th edition, pg. 669, 674","responses":[{"text":"Pituitary failure/Sheehan's syndrome","correct":false,"visible":false},{"text":"Hypogonadotrophic hypogonadism","correct":false,"visible":false},{"text":"Polyglandular autoimmune syndrome","correct":false,"visible":false},{"text":"Hypergonadotrophic hypogonadism","correct":true,"visible":false},{"text":"Celiac disease","correct":false,"visible":false}]},{"id":14256,"text":"A patient is admitted to the hospital due to diabetic ketoacidosis. After treatment, his blood glucose, pH, and serum osmolality stabilize to normal values. During the assessment, he complains of weakness in his legs. Which of the following is a priority intervention in this patient?","explanation":null,"reference":"Kumar and Clark's clinical medicine, 10th edition, pg. 723 - 724, box 23.19","responses":[{"text":"Allow uninterrupted rest period throughout the day","correct":false,"visible":false},{"text":"Ensure the patient is safe from falls and check the most recent potassium levels","correct":true,"visible":false},{"text":"Request a physical therapy consult from the physician","correct":false,"visible":false},{"text":"Encourage the patient to increase intake of dairy products and green vegetables","correct":false,"visible":false},{"text":"Check vitamin D levels","correct":false,"visible":false}]},{"id":14258,"text":"A 64-year-old male who is a known case of diabetes presents to the outpatient department for a regular follow-up. His glomerular filtration rate (GFR) is 28 ml/min and he is currently on mixed insulin and metformin. In the past six months he has had no hypoglycemic event. Which of the following is the most appropriate next step in his treatment?","explanation":null,"reference":"Davidson's principles and practice of medicine, 24th edition, pg. 735 - 736","responses":[{"text":"Decrease the dose of metformin and insulin","correct":false,"visible":false},{"text":"Stop metformin and start DPP-4 inhibitor","correct":false,"visible":false},{"text":"Stop insulin and metformin both and put him on short-acting sulphonylurea","correct":false,"visible":false},{"text":"Continue with the same treatment","correct":false,"visible":false},{"text":"Stop metformin and continue insulin","correct":true,"visible":false}]},{"id":14259,"text":"A middle-aged female presents to you with complaints of weight gain, swelling all over the body, constipation, and shortness of breath on mild to moderate exertion. Which of the following tests will you advise to diagnose this patient?","explanation":null,"reference":"Davidson's principles and practice of medicine, 24th edition, pg. 655 box 20.7 and pg. 657 figure 20.6","responses":[{"text":"Fasting blood sugar, lipid profile, serum insulin, and pelvic ultrasound","correct":false,"visible":false},{"text":"Thyroid profile and anti thyroid peroxidase (TPO) antibodies","correct":true,"visible":false},{"text":"Chest x-ray PA view","correct":false,"visible":false},{"text":"Echocardiography","correct":false,"visible":false},{"text":"Complete blood count with peripheral film","correct":false,"visible":false}]}
]

export default a